where po.tenant_id = #{tenantId} and bo.del_flag = 0
and po.status = #{statusCode}
and po.channel_id = #{channelId}
and ( po.pay_order_no like concat('%', #{keyword}, '%') or bo.biz_order_no like concat('%', #{keyword}, '%') or bo.title like concat('%', #{keyword}, '%') or po.channel_trade_no like concat('%', #{keyword}, '%') or m.method_name like concat('%', #{keyword}, '%') or m.method_code like concat('%', #{keyword}, '%') or c.channel_code like concat('%', #{keyword}, '%') or c.channel_name like concat('%', #{keyword}, '%') or po.channel_merchant_no like concat('%', #{keyword}, '%') or cc.merchant_no like concat('%', #{keyword}, '%') )

mapper.select:
select count(1)
from payment_order po
where po.tenant_id = #{tenantId}

  and po.status = #{status}



where po.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and po.id = #{id}
limit 1



where po.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and po.id = #{id}
limit 1



where po.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and bo.app_code = #{appId}
  and po.pay_order_no = #{payOrderNo}
limit 1



where po.tenant_id = #{tenantId}
  and bo.del_flag = 0
  and bo.app_code = #{appId}
  and bo.biz_order_no = #{bizOrderNo}
  and po.status = 'SUCCESS'
  and po.success_flag = 1
order by po.pay_time desc, po.created_at desc
limit 1

select flow_no
from payment_transaction_flow
where tenant_id = #{tenantId}
  and payment_order_id = #{paymentOrderId}
order by created_at desc
limit 1

select po.id, po.pay_order_no as payOrderNo, po.business_order_id as businessOrderId, po.cashier_config_id as cashierConfigId, po.channel_id as channelId, po.channel_code as channelCode, po.channel_merchant_no as channelMerchantNo, po.contract_id as contractId, po.contract_capability_id as contractCapabilityId, po.route_rule_id as routeRuleId, po.method_id as methodId, po.amount, po.status, po.channel_trade_no as channelTradeNo, po.success_flag as successFlag, po.pay_time as payTime, po.expire_time as expireTime, po.tenant_id as tenantId, po.created_by as createdBy, po.created_at as createdAt, po.updated_by as updatedBy, po.updated_at as updatedAt from payment_order po where po.tenant_id = #{tenantId} and po.channel_code = #{channelCode} and po.status = 'SUCCESS' and po.success_flag = 1 and po.channel_trade_no is not null and po.pay_time >= #{billDate} and po.pay_time < #{nextBillDate}
and po.channel_trade_no not in
#{channelTradeNo}
order by po.pay_time asc, po.channel_trade_no asc

select count(1)
from payment_order po
where po.tenant_id = #{tenantId}
  and po.business_order_id = #{businessOrderId}
  and po.status = 'SUCCESS'

select po.pay_order_no
from payment_order po
where po.tenant_id = #{tenantId}
  and po.business_order_id = #{businessOrderId}
  and po.method_id = #{methodId}
  and po.status = 'PAYING'
order by po.created_at desc
limit 1
